const markdown = $input.item.json.markdown || '';
const sourceURL = $input.item.json.metadata?.sourceURL || 'Unknown';

const result = {
  instagramEmbeds: [],
  facebookEmbeds: [],
  twitterEmbeds: [],
  youtubeEmbeds: [],
  images: [],
  otherEmbeds: [],
  sourceURL: sourceURL
};

// Extract Instagram embeds: Find URLs and generate HTML embed code
const instagramUrlRegex = /https:\/\/www\.instagram\.com\/(p|reel)\/[A-Za-z0-9_-]+\//g;
const instagramUrls = markdown.match(instagramUrlRegex) || [];
// Deduplicate Instagram URLs
const uniqueInstagramUrls = [...new Set(instagramUrls)];
result.instagramEmbeds = uniqueInstagramUrls.map(url => {
  return `<blockquote class="instagram-media" data-instgrm-permalink="${url}" data-instgrm-version="14" style="max-width:540px; width:100%;">
    <a href="${url}">View this post on Instagram</a>
  </blockquote>
  <script async src="//www.instagram.com/embed.js"></script>`;
});

// Extract Facebook embeds (if present as HTML)
const facebookRegex = /<iframe[^>]*src="[^"]*facebook\.com[^"]*"[^>]*>.*?<\/iframe>/gs;
const facebookMatches = markdown.match(facebookRegex) || [];
// Deduplicate Facebook embeds
result.facebookEmbeds = [...new Set(facebookMatches)];

// Extract Twitter/X embeds (if present as HTML)
const twitterRegex = /<blockquote[^>]*class="[^"]*twitter-tweet[^"]*"[^>]*>.*?<\/blockquote>\s*<script[^>]*src="[^"]*platform\.twitter\.com\/widgets\.js"[^>]*><\/script>/gs;
const twitterMatches = markdown.match(twitterRegex) || [];
// Deduplicate Twitter embeds
result.twitterEmbeds = [...new Set(twitterMatches)];

// Extract YouTube embeds (if present as HTML)
const youtubeRegex = /<iframe[^>]*src="[^"]*(?:youtube\.com|youtu\.be)[^"]*"[^>]*>.*?<\/iframe>/gs;
const youtubeMatches = markdown.match(youtubeRegex) || [];
// Deduplicate YouTube embeds
result.youtubeEmbeds = [...new Set(youtubeMatches)];

// Extract markdown images ![alt](url)
const markdownImageRegex = /!\[([^\]]*)\]\(([^)]+)\)/g;
let match;
const imageMap = new Map();
while ((match = markdownImageRegex.exec(markdown)) !== null) {
  const url = match[2];
  if (!imageMap.has(url)) {
    imageMap.set(url, {
      alt: match[1],
      url: url,
      type: 'markdown'
    });
  }
}

// Extract HTML img tags
const htmlImageRegex = /<img[^>]*src="([^"]*)"[^>]*(?:alt="([^"]*)")?[^>]*>/g;
while ((match = htmlImageRegex.exec(markdown)) !== null) {
  const url = match[1];
  if (!imageMap.has(url)) {
    imageMap.set(url, {
      url: url,
      alt: match[2] || '',
      type: 'html'
    });
  }
}

// Convert Map to array
result.images = Array.from(imageMap.values());

// Extract other iframes (TikTok, Vimeo, etc.)
const otherIframeRegex = /<iframe[^>]*src="([^"]*)"[^>]*>.*?<\/iframe>/gs;
const allIframes = markdown.match(otherIframeRegex) || [];
const otherIframes = allIframes.filter(iframe =>
  !iframe.includes('facebook.com') &&
  !iframe.includes('youtube.com') &&
  !iframe.includes('youtu.be')
);
// Deduplicate other embeds
result.otherEmbeds = [...new Set(otherIframes)];

return result;

const allData = $input.all().map(item => item.json.data).flat();

const globalInstagramSet = new Set();
const globalFacebookSet = new Set();
const globalTwitterSet = new Set();
const globalYoutubeSet = new Set();
const globalImageMap = new Map();
const globalOtherSet = new Set();

// Collect all embeds and images from all pages
for (const pageData of allData) {
  // Instagram embeds
  if (pageData.instagramEmbeds) {
    pageData.instagramEmbeds.forEach(embed => globalInstagramSet.add(embed));
  }

  // Facebook embeds
  if (pageData.facebookEmbeds) {
    pageData.facebookEmbeds.forEach(embed => globalFacebookSet.add(embed));
  }

  // Twitter embeds
  if (pageData.twitterEmbeds) {
    pageData.twitterEmbeds.forEach(embed => globalTwitterSet.add(embed));
  }

  // YouTube embeds
  if (pageData.youtubeEmbeds) {
    pageData.youtubeEmbeds.forEach(embed => globalYoutubeSet.add(embed));
  }

  // Images (deduplicate by URL)
  if (pageData.images) {
    pageData.images.forEach(img => {
      if (!globalImageMap.has(img.url)) {
        globalImageMap.set(img.url, img);
      }
    });
  }

  // Other embeds
  if (pageData.otherEmbeds) {
    pageData.otherEmbeds.forEach(embed => globalOtherSet.add(embed));
  }
}

// Return deduplicated results
return {
  instagramEmbeds: Array.from(globalInstagramSet),
  facebookEmbeds: Array.from(globalFacebookSet),
  twitterEmbeds: Array.from(globalTwitterSet),
  youtubeEmbeds: Array.from(globalYoutubeSet),
  images: Array.from(globalImageMap.values()),
  otherEmbeds: Array.from(globalOtherSet)
};

